import{_ as s,c as n,o as a,U as p}from"./chunks/framework.9QHaLlVJ.js";const i="/assets/1460000018048959.jSBS8z8B.png",g=JSON.parse('{"title":"php-fpm","description":"","frontmatter":{},"headers":[],"relativePath":"doc/编程语言/PHP/底层原理/php-fpm.md","filePath":"packages/doc/src/编程语言/PHP/底层原理/php-fpm.md","lastUpdated":1704643216000}'),e={name:"doc/编程语言/PHP/底层原理/php-fpm.md"},l=p(`<h1 id="php-fpm" tabindex="-1">php-fpm <a class="header-anchor" href="#php-fpm" aria-label="Permalink to &quot;php-fpm&quot;">​</a></h1><h2 id="php-fpm-介绍" tabindex="-1">PHP-FPM 介绍 <a class="header-anchor" href="#php-fpm-介绍" aria-label="Permalink to &quot;PHP-FPM 介绍&quot;">​</a></h2><h3 id="cgi-协议与-fastcgi-协议" tabindex="-1">CGI 协议与 FastCGI 协议 <a class="header-anchor" href="#cgi-协议与-fastcgi-协议" aria-label="Permalink to &quot;CGI 协议与 FastCGI 协议&quot;">​</a></h3><p>每种动态语言（ PHP,Python 等）的代码文件需要通过对应的解析器才能被服务器识别，而 CGI 协议就是用来使解释器与服务器可以互相通信。PHP 文件在服务器上的解析需要用到 PHP 解释器，再加上对应的 CGI 协议，从而使服务器可以解析到 PHP 文件。</p><p>由于 CGI 的机制是每处理一个请求需要 fork 一个 CGI 进程，请求结束再kill掉这个进程，在实际应用上比较浪费资源，于是就出现了CGI 的改良版本 FastCGI，FastCGI 在请求处理完后，不会 kill 掉进程，而是继续处理多个请求，这样就大大提高了效率。</p><h3 id="php-fpm-是什么" tabindex="-1">PHP-FPM 是什么 <a class="header-anchor" href="#php-fpm-是什么" aria-label="Permalink to &quot;PHP-FPM 是什么&quot;">​</a></h3><p>PHP-FPM 即 PHP-FastCGI Process Manager， 它是 FastCGI 的实现，并提供了进程管理的功能。进程包含 master 进程和 worker 进程两种；master 进程只有一个，负责监听端口，接收来自服务器的请求，而 worker 进程则一般有多个（具体数量根据实际需要进行配置），每个进程内部都会嵌入一个 PHP 解释器，是代码真正执行的地方。</p><h2 id="nginx-与-php-fpm-通信机制" tabindex="-1">Nginx 与 php-fpm 通信机制 <a class="header-anchor" href="#nginx-与-php-fpm-通信机制" aria-label="Permalink to &quot;Nginx 与 php-fpm 通信机制&quot;">​</a></h2><p>当我们访问一个网站（如 www.test.com）的时候，处理流程是这样的：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>  www.test.com</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>      Nginx</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>路由到 www.test.com/index.php</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>加载 nginx 的 fast-cgi 模块</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>fast-cgi 监听 127.0.0.1:9000 地址</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>www.test.com/index.php 请求到达 127.0.0.1:9000</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>     等待处理...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><h3 id="nginx-与-php-fpm-的结合" tabindex="-1">Nginx 与 php-fpm 的结合 <a class="header-anchor" href="#nginx-与-php-fpm-的结合" aria-label="Permalink to &quot;Nginx 与 php-fpm 的结合&quot;">​</a></h3><p>在 Linux 上，nginx 与 php-fpm 的通信有 tcp socket 和 unix socket 两种方式。</p><p>tcp socket 的优点是可以跨服务器，当 nginx 和 php-fpm 不在同一台机器上时，只能使用这种方式。</p><p>Unix socket 又叫 IPC(inter-process communication 进程间通信) socket，用于实现同一主机上的进程间通信，这种方式需要在 nginx配置文件中填写 php-fpm 的 socket 文件位置。</p><p>两种方式的数据传输过程如下图所示： <img src="`+i+`" alt="img"></p><p>二者的不同：</p><p>由于 Unix socket 不需要经过网络协议栈，不需要打包拆包、计算校验和、维护序号和应答等，只是将应用层数据从一个进程拷贝到另一个进程。所以其效率比 tcp socket 的方式要高，可减少不必要的 tcp 开销。不过，unix socket 高并发时不稳定，连接数爆发时，会产生大量的长时缓存，在没有面向连接协议的支撑下，大数据包可能会直接出错不返回异常。而 tcp 这样的面向连接的协议，可以更好的保证通信的正确性和完整性。</p><p>Nginx 与 php-fpm 结合只需要在各自的配置文件中做设置即可：</p><p>1） Nginx 中的配置</p><p>以 tcp socket通信为例</p><div class="language-nginx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    listen </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      80</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#监听 80 端口，接收http请求</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    server_name </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> www.test.com; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#就是网站地址</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    root </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/usr/local/etc/nginx/www/huxintong_admin; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 准备存放代码工程的路径</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    #路由到网站根目录 www.test.com 时候的处理</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> / </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        index </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index.php; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#跳转到 www.test.com/index.php</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        autoindex </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">on;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }   </span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    #当请求网站下 php 文件的时候，反向代理到 php-fpm</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    location</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ~</span><span style="--shiki-light:#032F62;--shiki-dark:#DBEDFF;"> \\.php$ </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        include </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/usr/local/etc/nginx/fastcgi.conf; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#加载 nginx 的 fastcgi 模块</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        fastcgi_intercept_errors </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">on;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        fastcgi_pass </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  127.0.0.1:9000; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># tcp 方式，php-fpm 监听的 IP 地址和端口</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # fasrcgi_pass /usr/run/php-fpm.sock # unix socket 连接方式</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p>\\2) php-fpm 的配置</p><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">listen</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 127.0.0.1:9000</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或者下面这样</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">listen</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = /var/run/php-fpm.sock</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><blockquote><p>注意，在使用 unix socket 方式连接时，由于 socket 文件本质上是一个文件，存在权限控制的问题，所以需要注意 nginx 进程的权限与 php-fpm 的权限问题，不然会提示无权限访问。（在各自的配置文件里设置用户）</p></blockquote><p>通过以上配置即可完成 php-fpm 与 nginx 的通信。</p><h3 id="在应用中的选择" tabindex="-1">在应用中的选择 <a class="header-anchor" href="#在应用中的选择" aria-label="Permalink to &quot;在应用中的选择&quot;">​</a></h3><p>如果是在同一台服务器上运行的 nginx 和 php-fpm，且并发量不高（不超过1000），选择unix socket，以提高 nginx 和 php-fpm 的通信效率。 如果是面临高并发业务，则考虑选择使用更可靠的 tcp socket，以负载均衡、内核优化等运维手段维持效率。</p><p>若并发较高但仍想用 unix socket 时，可通过以下方式提高 unix socket 的稳定性。</p><p>1）将sock文件放在 /dev/shm 目录下，此目录下将 sock 文件放在内存里面，内存的读写更快。</p><p>2）提高 backlog</p><p>backlog 默认位 128，1024 这个值最好换算成自己正常的 QPS，配置如下。</p><p>nginx.conf 文件中</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        listen </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">80</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> backlog </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1024</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">       }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>php-fpm.conf 文件中</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>listen.backlog = 1024</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>3）增加 sock 文件和 php-fpm 实例</p><p>在 /dev/shm 新建一个 sock 文件，在 nginx 中通过 upstream 模块将请求负载均衡到两个 sock 文件，并且将两个 sock 文件分别对应到两套 php-fpm 实例上。</p>`,37),t=[l];function h(r,c,k,d,o,m){return a(),n("div",null,t)}const u=s(e,[["render",h]]);export{g as __pageData,u as default};
